var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EMPLOYEE_FRONTBAY_NULL_ADMIN","text":{"KOREA":"대균열 심부로부터 정령 소재의 반응을 확보했습니다.","JPN":"大亀裂の深部から精霊素材の反応を確保しました。","ENG":"We've detected Elemental signals coming from the depths of the Grand Dimension Crevice.","TWN":"我們已經從大峽谷深處獲得了精靈的反應訊號。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"예상 밖의 전개군. 그자가 심부에서 셰퍼드를 직접 완성시킬 줄은 몰랐어.","JPN":"予想外の展開だな。あの者が深部でシェパードを直接完成させるとは。","ENG":"That's unexpected. Who would've thought that she would complete Shepherd in the depths.","TWN":"意想不到的發展。誰能知道她會親手完成了牧羊犬呢？"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"다음 계획을 서두르는 게 좋겠군.","JPN":"急いで次の計画に移ったほうがよさそうだ。","ENG":"It's time we hurried on with our next plan.","TWN":"下一個計畫，要開始著手準備了。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"…힉스.","JPN":"……ヒックス。","ENG":"...Hicks.","TWN":"……希克斯。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"힉…? 으극…?!","JPN":"ひっ……？　うぐっ……！？","ENG":"Eep...? Ngh...?!","TWN":"呼……？啊……？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_11"},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"파하아…! 부르셨나요?","JPN":"ぷはあ……！　お呼びですか？","ENG":"Paah...! You called?","TWN":"噗哈……！你找我？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"귀가 머리째로 박살나는 바람에 뭐라고 말씀하시는지 잘 못 들었어요.","JPN":"耳が頭と一緒に潰されて、なんておっしゃったのか聞こえませんでした。","ENG":"I couldn't hear you clearly because my head was cracked open along with my ears.","TWN":"我聽不清你在說什麼，我的耳朵剛剛破掉了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"지금 당장 셰퍼드를 회수하고, 기지를 폭파시켜 모든 데이터 기록을 말소해라.","JPN":"今すぐシェパードを回収し、基地を爆発させてすべてのデータ記録を抹消しろ。","ENG":"Go fetch Shepherd, and detonate the base to erase all data records.","TWN":"立即找回牧羊犬，炸毀基地並清除所有資料記錄。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"신성반응을 관측하고 있는 건 우리뿐만이 아니다. 방해꾼이 붙기 전에 최대한 빨리 끝내도록.","JPN":"神聖反応を観測しているのは俺たちだけではない。邪魔者ができるまえに、なるべく早く終わらせるんだ。","ENG":"We're not the only ones observing the Divinity response. Finish the job as quickly as possible before anyone interrupts us.","TWN":"我們並不是唯一觀測到神聖反應的人。在妨礙的人介入之前，盡快完成這件事。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네, 알겠습니다.","JPN":"はい、わかりました。","ENG":"Yes, sir.","TWN":"嗯，我知道了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"우으웁, 내 피냄새…","JPN":"ううう、私の血の匂い……","ENG":"Oof, I smell like blood...","TWN":"噢，渾身都是血的味道……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"휴, 좀 살겠다. 향수병이 안 깨져서 다행이야.","JPN":"ふう、ちょっとマシになった。香水の瓶が割れなくてよかったね。","ENG":"Phew! That's better. Lucky that my perfume bottle didn't break.","TWN":"呼，得救了，還好香水瓶沒有裂開。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"킁킁- 피 냄새가 이것저것 섞여 있네.","JPN":"くんくん、血の匂いが混ざってる。","ENG":"*Sniff, sniff* Looks like the smell of blood is mixed with other stuff.","TWN":"噢噢——血的味道，和其他什麼東西混合在一起了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"스펜서의 냄새를 바로 쫓아가도 되겠지만…","JPN":"スペンサーの匂いをすぐ追ってもいいけど……","ENG":"I could just follow Spencer's smell to chase her, but...","TWN":"找到了，史賓瑟的氣味，不過……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"갈증부터 채우고 가도 되겠지?","JPN":"渇きから解決してもいいよね？","ENG":"I guess I can quench my thirst before, right?","TWN":"還是得先解解渴吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"설계도를 아무리 뒤져도 없어.","JPN":"いくら設計図を見ても見つからない。","ENG":"I looked at the blueprints, but there's nothing.","TWN":"我怎麼也找不到設計圖。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"역시, 시설 내부에 다이빙 벨은 거기 하나뿐이었던 건가?","JPN":"やっぱり、施設内部にダイビングベルはあそこに一つしかなかったのか？","ENG":"Is there only one Diving Bell within this facility?","TWN":"果然，設施內只有一個潛水鐘嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"으윽…! 하아… 하…","JPN":"ううっ……！　はあ……はあ……","ENG":"Ngh...! *Huff...* *Huff...*","TWN":"呃……！呼呼……呼……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"많이 아파요?","JPN":"痛い？","ENG":"Does it hurt a lot?","TWN":"很痛嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래… 좀 힘드네.","JPN":"ええ……ちょっとね。","ENG":"Yeah... A little.","TWN":"沒錯……有一點。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그 병은 어떻게 해야 나아요?","JPN":"その病気は、どうしたら治るの？","ENG":"How do you get better from it?","TWN":"史賓瑟怎樣才會好一點呢？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"글쎄.","JPN":"わからない。","ENG":"I dunno.","TWN":"不清楚。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나도 그걸 오랫동안 연구했지만, 결국 방법은 찾지 못했어.","JPN":"私も長い間そのことを研究してきたけど、結局方法が見つからなかったんだ。","ENG":"I've researched it for a long time, but I couldn't find a cure.","TWN":"我也研究了很久，但還是沒有找到方法。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"일단, 살아남으려면 여길 먼저 벗어나야 해.","JPN":"とりあえず、生き残るためにはここから出ないと。","ENG":"First, we need to get out of here if we want to live.","TWN":"首先，想要活下去，就必須先離開這裡。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"현실세계. 당신도 거기 가고 싶은 거죠?","JPN":"ノーマルサイド。あなたもそこに行きたいの？","ENG":"The Normalside. Do you also want to go there?","TWN":"現實世界。你想去那裡，對嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…맞아.","JPN":"……そう。","ENG":"...Yes.","TWN":"……沒錯。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"너도 알고 있니?","JPN":"あなたも知ってる？","ENG":"Do you know about it?","TWN":"你知道怎麼走嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하늘에 별이 보이고, 얼음이 내리는 겨울이 있는 세상.","JPN":"空には星が見えて、氷が降る冬がある世界。","ENG":"It's a world where the sky has stars and ice falls down in winter.","TWN":"那個天空中可以看到星星、冬天可以看到冰雪的世界。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"날 아끼는 사람이 선물 상자에 그려둔 길로 가면 돌아갈 수 있댔어요.","JPN":"シェパードを大切に思っている人が、プレゼントボックスに描いた道のとおりに行くと戻れるんだって。","ENG":"The person dear to Shepherd said there's a way out if Shepherd follows the path he drew on Shepherd's gift box.","TWN":"在乎牧羊犬的人說，只要按照禮物盒上畫的路走就可以過去。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"선물 상자라고?","JPN":"プレゼントボックス？","ENG":"Gift box?","TWN":"禮物盒？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 설계도… 터미널에서 본 것과 구조가 달라.","JPN":"この設計図……ターミナルで見たのと構造が違う。","ENG":"This blueprint... It's different from the one I saw at the terminal.","TWN":"這張設計圖……它的結構與我在終端中看到的不同。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"설계도에 없던 방을 표시해 둔 건가?","JPN":"設計図になかった部屋を示しておいたのか？","ENG":"Has he marked the rooms that aren't on the blueprint?","TWN":"他還標記了設計圖中沒有的房間？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 맨 아래층은 총 든 무서운 어른들이랑 아무나 못 들어가는 특별한 방이 많대요.","JPN":"うん、一番下は銃を持ってる怖い大人たちと、特定の人だけ入れる特別な部屋が多いんだって。","ENG":"Uh-huh. He said there's a special room on the bottom floor full of scary adults with guns that only special people can enter.","TWN":"嗯、嗯，聽說底層全是持槍的可怕大人，還有很多沒人能進入的特殊房間。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하지만 지금은 아무도 지키고 있지 않으니까, 거기로 가면 된다고 했어요.","JPN":"でも今はそこを見張ってる人が誰もいないから、そこに行けばいいって言ってた。","ENG":"But there shouldn't be anyone guarding it now, so he said Shepherd should go there.","TWN":"不過現在沒人看守，我們能過去了。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신도 나랑 같이 가요.","JPN":"あなたもシェパードと一緒に行こうよ。","ENG":"You should come with Shepherd.","TWN":"史賓瑟也跟牧羊犬一起吧。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"가겠다고…?","JPN":"行く……？","ENG":"You're going...?","TWN":"你要去……？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말이니? 여기 남지 않고, 같이 가도 괜찮은 거야?","JPN":"本当？　ここに残らず、一緒に行っても大丈夫なのか？","ENG":"Really? Is it okay for you to come with me and not stay here?","TWN":"你認真的？牧羊犬不留在這裡也沒關係嗎？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응.","JPN":"うん。","ENG":"Uh-huh.","TWN":"嗯。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"반짝반짝 눈 내리는 밤하늘 보고 싶어요. 함께.","JPN":"キラキラ雪が降る夜空、見たい。一緒に。","ENG":"Shepherd wants to see the night sky with twinkling snow, together.","TWN":"牧羊犬想看看夜空中飄揚的雪花。和史賓瑟一起。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Okay.","TWN":"……好。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리 같이 가자.","JPN":"一緒に行こう。","ENG":"Then let's go together.","TWN":"一起走吧。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"가기 전에… 자장가 불러도 돼요?","JPN":"行く前に……子守歌を歌ってもいい？","ENG":"Before we go... can Shepherd sing a lullaby?","TWN":"在走之前……可以唱首搖籃曲嗎？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그러렴.","JPN":"ええ。","ENG":"Sure.","TWN":"當然。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…잘 자라. 우리 아가.","JPN":"……ね〜んね。私の赤ちゃん。","ENG":"...Sleep well. Baby.","TWN":"……寶寶睡， 寶寶睡。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_RAS_MA_DINO_IN_TRAILER_3"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"아름다운 꽃이, 너를 둘러 피었네.","JPN":"美しい花が、あなたの周りに咲きほこる。","ENG":"The beautiful flowers have blossomed around you.","TWN":"美麗的花兒伴你入睡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"창문으로 아침이 찾아올 때까지.","JPN":"窓から朝がやって来るまで。","ENG":"Until the morning sun shines through your window.","TWN":"睡個好覺吧~直到清晨的太陽將你輕偎。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"낙원의 단꿈을 꾸며, 잘 자거라.","JPN":"楽園の甘い夢を見て、お休み。","ENG":"Dream of paradise in your sleep, and sweet dreams.","TWN":"做個天堂般的美夢，讓我們在夢中相會。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"잘 자라… 우리… 아가.","JPN":"ね〜んね……私の……赤ちゃん。","ENG":"Sleep well... Ba... by.","TWN":"晚安……我最親愛的……寶貝。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"날 아끼는 사람이 불러줬어.","JPN":"シェパードを大切に思っている人が歌ってくれた。","ENG":"The person dear to Shepherd sang me that song.","TWN":"有一個在乎牧羊犬的人經常這麼唱。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"이 노래를 들으면, 편하게 잠들 수 있거든요.","JPN":"この歌を聞くと、安心して眠れるの。","ENG":"When Shepherd hears it, Shepherd can fall asleep comfortably.","TWN":"聽著這首歌，牧羊犬就可以很舒服地入睡。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇구나.","JPN":"そうなの。","ENG":"I see.","TWN":"原來是這樣。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 사람이… 너에게 참 많은 걸 가르쳐준 모양이네.","JPN":"あの人が……あなたにたくさんのことを教えてあげたようだな。","ENG":"This person... seems to have taught you a lot of things.","TWN":"那個人……看來教了你很多東西。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"사실 알고 있었어요.","JPN":"実は、わかってたの。","ENG":"Shepherd actually knows.","TWN":"牧羊犬其實都知道。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"심장이 멈추면, 다신 깨어나지 않는 거.","JPN":"心臓が止まれば、もう目覚めることはできないって。","ENG":"That when the heart stops, people don't wake up again.","TWN":"心臟如果停止跳動，人就不會再醒來了。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"기계가 아니니까. 충전하려고 쉰다는 것도… 거짓말인 거 알았어요.","JPN":"機械じゃないから。充電するために休むってのも……ウソだってわかってた。","ENG":"They're not machines. Shepherd knows that he was lying... when he said that he needed to recharge and rest.","TWN":"他不是機器。說要充電休息一下……牧羊犬知道這是一個謊言。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼… 왜 계속 여기 남아있었던 거야?","JPN":"じゃあ……どうしてずっとここに残ってたんだ？","ENG":"Then... why did you continue to stay here?","TWN":"那……你為什麼還留在這裡？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"약속했어요.","JPN":"約束したんだ。","ENG":"Because Shepherd promised.","TWN":"因為約定。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"여길 떠나지 않고, 잘 숨어있기로.","JPN":"ここから出ないで、ちゃんと隠れてるって。","ENG":"Shepherd promised to not leave and stay hidden.","TWN":"牧羊犬不會離開這裡，要好好躲起來。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"마지막 약속이니까. 지키고 싶었어요.","JPN":"最後の約束だから。守りたかったの。","ENG":"It was the last promise, so Shepherd wanted to keep it.","TWN":"這是牧羊犬和他最後的約定。牧羊犬想遵守約定。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드…….","JPN":"シェパード……","ENG":"Shepherd...","TWN":"牧羊犬……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하지만 당신은 내가 다치면 괴로워해요.","JPN":"でも、あなたはシェパードが怪我すると苦しむ。","ENG":"But you suffer when Shepherd gets hurt.","TWN":"但當牧羊犬受傷時，史賓瑟會很痛苦。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"내가 그 약속 때문에 도망치면 슬퍼하고요.","JPN":"シェパードがその約束のせいで逃げたら悲しむ。","ENG":"And get sad when Shepherd runs away because of the promise.","TWN":"牧羊犬因為約定逃跑了，史賓瑟會很難過。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드는 당신이 아프지 않았으면 좋겠어. 당신이 행복했으면 좋겠어요.","JPN":"シェパードは、あなたに元気になってほしい。あなたが幸せであってほしい。","ENG":"Shepherd doesn't want you to be in pain. Shepherd wants you to be happy.","TWN":"牧羊犬希望史賓瑟不要難過，希望你能開心。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그러니까, 이젠 솔직하게 말할래요.","JPN":"だから、もう素直に話すね。","ENG":"So, it's time Shepherd was honest with you.","TWN":"所以，現在牧羊犬要坦率地和史賓瑟說出心裡話——"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신이랑 같이 가고 싶어요.","JPN":"あなたと一緒に行きたい。","ENG":"Shepherd wants to go with you.","TWN":"牧羊犬想要和你一起去外面。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그래도 돼요?","JPN":"いいかな？","ENG":"Can Shepherd do that?","TWN":"可以嗎？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…물론이지.","JPN":"……もちろん。","ENG":"...Of course.","TWN":"……當然可以。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇게 하자.","JPN":"そうしよう。","ENG":"Let's do that.","TWN":"一起走吧，我們。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하지만 조심해야 돼.","JPN":"でも、気をつけて。","ENG":"But be careful.","TWN":"不過一定要小心。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 고철괴물이 아직 근처를 어슬렁대고 있을 테니까.","JPN":"あの鉄くずの化け物が、まだ辺りをうろついているはずだから。","ENG":"That scrap metal monster might still be lurking around here somewhere.","TWN":"那個廢鐵怪物可能還在附近徘徊。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"괜찮아요. 러처 만나면 그땐 내가 막으면 돼요.","JPN":"大丈夫。ラッチャーに会ったら、その時にはシェパードが止めればいい。","ENG":"It's okay. Shepherd will stop Lurcher if we meet him.","TWN":"沒關係。如果遇到獵犬，牧羊犬會阻止它。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아니, 뻔한 결과를 두 번 되풀이 할 순 없어.","JPN":"いや、同じことを二度も繰り返すわけにはいかない。","ENG":"No, I won't let the same obvious result happen twice.","TWN":"不，那樣的後果我不想再有第二次了。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"놈을 마주치면, 최대한 도망쳐. 알겠지?","JPN":"やつに出くわしたら、なるべく逃げなさい。わかった？","ENG":"If we run into it, run as far away from it as you can, okay?","TWN":"如果遇到它，要盡量逃跑。知道了嗎？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"잘 자, 내가… 가장 아끼는 사람.","JPN":"おやすみ、シェパードの……一番大切な人。","ENG":"Sleep well, the person... Shepherd cherishes the most.","TWN":"睡個好覺吧，牧羊犬……最在乎的人。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_RAS_MA_DINO_IN_TRAILER_4"}]`);export{e as default};